function initials(name) {
  return name.split(' ').slice(-2).map(w => w[0]).join('');
}

// ── Panel Components ────────────────────────────────────────────────────────

const AVATAR_COLORS_ATT = ['#3b82f6','#a855f7','#22c55e','#f97316','#ec4899','#ef4444','#14b8a6','#f59e0b','#6366f1','#84cc16'];

function AttendancePanel() {
  const storageKey = 'lasu_attendance_records';
  const loadRecords = () => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) return JSON.parse(saved);
    } catch(e) {}
    return STAFF.map((s, i) => ({ ...s, id: Date.now() + i, status: 'present', color: AVATAR_COLORS_ATT[i % AVATAR_COLORS_ATT.length] }));
  };

  const [records, setRecords] = useState(loadRecords);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [form, setForm] = useState({ name: '', role: '', dept: '', status: 'present' });
  const [formErrors, setFormErrors] = useState({});
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [exportMsg, setExportMsg] = useState('');
  const [pdfLoading, setPdfLoading] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(null);

  // Persist to localStorage whenever records change
  useEffect(() => {
    localStorage.setItem(storageKey, JSON.stringify(records));
  }, [records]);

  const count = (s) => records.filter(r => r.status === s).length;
  const total = records.length;

  const filtered = records.filter(r => {
    const matchSearch = r.name.toLowerCase().includes(search.toLowerCase()) ||
                        r.role.toLowerCase().includes(search.toLowerCase()) ||
                        (r.dept||'').toLowerCase().includes(search.toLowerCase());
    const matchStatus = filterStatus === 'all' || r.status === filterStatus;
    return matchSearch && matchStatus;
  });

  const badge = {
    present: 'bg-green-100 text-green-700 border border-green-200',
    absent:  'bg-red-100 text-red-700 border border-red-200',
    late:    'bg-yellow-100 text-yellow-700 border border-yellow-200',
    excused: 'bg-blue-100 text-blue-700 border border-blue-200',
  };

  const updateStatus = (id, status) =>
    setRecords(r => r.map(x => x.id === id ? { ...x, status } : x));

  const validateForm = () => {
    const errs = {};
    if (!form.name.trim()) errs.name = 'Name is required';
    else if (form.name.trim().length < 2) errs.name = 'Name too short';
    if (!form.role.trim()) errs.role = 'Role/Title is required';
    return errs;
  };

  const openAdd = () => {
    setEditingId(null);
    setForm({ name: '', role: '', dept: '', status: 'present' });
    setFormErrors({});
    setShowForm(true);
  };

  const openEdit = (record) => {
    setEditingId(record.id);
    setForm({ name: record.name, role: record.role, dept: record.dept || '', status: record.status });
    setFormErrors({});
    setShowForm(true);
  };

  const saveForm = () => {
    const errs = validateForm();
    if (Object.keys(errs).length) { setFormErrors(errs); return; }
    if (editingId) {
      setRecords(r => r.map(x => x.id === editingId
        ? { ...x, name: form.name.trim(), role: form.role.trim(), dept: form.dept.trim(), status: form.status }
        : x));
    } else {
      const colorIdx = records.length % AVATAR_COLORS_ATT.length;
      setRecords(r => [...r, {
        id: Date.now(),
        name: form.name.trim(),
        role: form.role.trim(),
        dept: form.dept.trim(),
        status: form.status,
        color: AVATAR_COLORS_ATT[colorIdx],
      }]);
    }
    setShowForm(false);
    setEditingId(null);
  };

  const deleteRecord = (id) => {
    setRecords(r => r.filter(x => x.id !== id));
    setConfirmDelete(null);
  };

  // ── PDF Export using jsPDF loaded dynamically ──
  const exportPDF = () => {
    setPdfLoading(true);
    const now = new Date();
    const dateStr = now.toLocaleDateString('en-GB', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
    const timeStr = now.toLocaleTimeString('en-GB', { hour:'2-digit', minute:'2-digit' });
    const pct = total > 0 ? Math.round((count('present') / total) * 100) : 0;

    const statusStyle = {
      present: 'background:#dcfce7;color:#15803d;',
      absent:  'background:#fee2e2;color:#b91c1c;',
      late:    'background:#fef9c3;color:#a16207;',
      excused: 'background:#dbeafe;color:#1e40af;',
    };

    const rows = records.map((r, i) => `
      <tr style="background:${i % 2 === 0 ? '#fff' : '#f8fafc'}">
        <td style="text-align:center;color:#64748b;font-size:11px">${i + 1}</td>
        <td style="font-weight:600;color:#1e293b">${r.name}</td>
        <td style="color:#475569">${r.role}</td>
        <td style="color:#475569">${r.dept || '—'}</td>
        <td style="text-align:center">
          <span style="padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;${statusStyle[r.status] || ''}">
            ${r.status.charAt(0).toUpperCase() + r.status.slice(1)}
          </span>
        </td>
        <td style="border-bottom:1px solid #cbd5e1;min-width:80px">&nbsp;</td>
      </tr>`).join('');

    const html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8"/>
  <title>LASU Attendance Register</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: Arial, sans-serif; color: #1e293b; background: #fff; }
    .header { background: #1e3a8a; color: #fff; padding: 24px 32px; text-align: center; }
    .header h1 { font-size: 22px; font-weight: 800; letter-spacing: 1px; margin-bottom: 4px; }
    .header h2 { font-size: 13px; font-weight: 400; opacity: 0.85; margin-bottom: 6px; }
    .header .meta { font-size: 11px; opacity: 0.7; }
    .summary { display: flex; justify-content: center; gap: 12px; padding: 20px 32px 10px; }
    .sum-box { flex: 1; max-width: 110px; border-radius: 10px; padding: 12px 8px; text-align: center; }
    .sum-box .val { font-size: 28px; font-weight: 800; }
    .sum-box .lbl { font-size: 10px; text-transform: uppercase; letter-spacing: 0.08em; margin-top: 2px; }
    .rate { text-align:center; font-size:13px; font-weight:700; color:#1e3a8a; padding-bottom:16px; }
    table { width: calc(100% - 64px); margin: 0 32px; border-collapse: collapse; font-size: 12px; }
    thead tr { background: #1e3a8a; color: #fff; }
    thead th { padding: 10px 8px; text-align: left; font-size: 11px; text-transform: uppercase; letter-spacing: 0.06em; }
    thead th:first-child, thead th:last-child { text-align: center; }
    td { padding: 9px 8px; border-bottom: 1px solid #e2e8f0; vertical-align: middle; }
    .footer { margin: 24px 32px 0; border-top: 1px solid #e2e8f0; padding-top: 12px; text-align:center; color:#94a3b8; font-size:10px; }
    @media print {
      @page { size: A4; margin: 0; }
      body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
    }
  </style>
</head>
<body>
  <div class="header">
    <div style="display:flex;align-items:center;justify-content:center;gap:16px;margin-bottom:8px">
      <img id="lasu-logo-att" src="${LASU_LOGO_B64}" alt="LASU" style="width:60px;height:60px;border-radius:50%;border:3px solid rgba(255,255,255,0.4);object-fit:cover" />
      <div style="text-align:left">
        <h1>LAGOS STATE UNIVERSITY</h1>
        <h2>BOARDROOM ATTENDANCE REGISTER</h2>
      </div>
    </div>
    <div class="meta">Generated: ${dateStr} &nbsp;|&nbsp; ${timeStr}</div>
  </div>

  <div class="summary">
    <div class="sum-box" style="background:#1e3a8a;color:#fff">
      <div class="val">${total}</div><div class="lbl">Total</div>
    </div>
    <div class="sum-box" style="background:#dcfce7;color:#15803d">
      <div class="val">${count('present')}</div><div class="lbl">Present</div>
    </div>
    <div class="sum-box" style="background:#fee2e2;color:#b91c1c">
      <div class="val">${count('absent')}</div><div class="lbl">Absent</div>
    </div>
    <div class="sum-box" style="background:#fef9c3;color:#a16207">
      <div class="val">${count('late')}</div><div class="lbl">Late</div>
    </div>
    <div class="sum-box" style="background:#dbeafe;color:#1e40af">
      <div class="val">${count('excused')}</div><div class="lbl">Excused</div>
    </div>
  </div>
  <div class="rate">Attendance Rate: ${pct}%</div>

  <table>
    <thead>
      <tr>
        <th style="width:32px;text-align:center">#</th>
        <th>Full Name</th>
        <th>Role / Title</th>
        <th>Department</th>
        <th style="width:80px;text-align:center">Status</th>
        <th style="width:100px;text-align:center">Signature</th>
      </tr>
    </thead>
    <tbody>${rows}</tbody>
  </table>

  <div class="footer">
    This document was generated by the LASU Boardroom Interactive Suite &nbsp;•&nbsp; Confidential
  </div>

  <script>
    window.onload = function() {
      setTimeout(function() { window.print(); }, 400);
    };
  </script>
</body>
</html>`;

    const win = window.open('', '_blank', 'width=900,height=700');
    if (!win) {
      setExportMsg('❌ Pop-up blocked! Allow pop-ups for this site and try again.');
      setTimeout(() => setExportMsg(''), 5000);
      setPdfLoading(false);
      return;
    }
    win.document.write(html);
    win.document.close();
    // Inject logo after write to bypass base64 blocking in some browsers
    try {
      const logoEl = win.document.getElementById('lasu-logo-att');
      if (logoEl) logoEl.src = LASU_LOGO_B64;
    } catch(e) {}
    setExportMsg('✅ Print dialog opened — choose "Save as PDF"');
    setTimeout(() => setExportMsg(''), 5000);
    setPdfLoading(false);
  };

  return (
    <div>
      {/* Stats */}
      <div className="grid grid-cols-5 gap-2 mb-4">
        {[['Total', total, 'blue'],['Present', count('present'), 'green'],['Absent', count('absent'), 'red'],['Late', count('late'), 'yellow'],['Excused', count('excused'), 'purple']].map(([l,v,c]) => (
          <div key={l} className={`text-center py-2.5 rounded-xl bg-${c}-50 border border-${c}-200`}>
            <div className={`text-xl font-bold text-${c}-600`}>{v}</div>
            <div className="text-xs text-gray-500 mt-0.5">{l}</div>
          </div>
        ))}
      </div>

      {/* Toolbar */}
      <div className="flex flex-wrap gap-2 mb-4">
        <input value={search} onChange={e => setSearch(e.target.value)}
          placeholder="🔍 Search members..."
          className="flex-1 min-w-0 px-3 py-2 border border-gray-200 rounded-xl text-sm outline-none focus:border-blue-400" />
        <select value={filterStatus} onChange={e => setFilterStatus(e.target.value)}
          className="px-3 py-2 border border-gray-200 rounded-xl text-sm outline-none bg-white cursor-pointer">
          <option value="all">All Status</option>
          <option value="present">Present</option>
          <option value="absent">Absent</option>
          <option value="late">Late</option>
          <option value="excused">Excused</option>
        </select>
      </div>

      {/* Member list */}
      <div className="mb-4 max-h-72 overflow-y-auto rounded-xl border border-gray-100">
        {filtered.length === 0 && (
          <div className="py-8 text-center text-gray-400 text-sm">No members match your search</div>
        )}
        {filtered.map((p) => (
          <div key={p.id} className="flex items-center gap-3 py-2.5 px-3 border-b border-gray-100 last:border-0 hover:bg-gray-50 transition-colors group">
            {/* Avatar */}
            <div className="w-9 h-9 rounded-full flex items-center justify-center text-white text-xs font-bold flex-shrink-0" style={{ background: p.color }}>
              {initials(p.name)}
            </div>
            {/* Info */}
            <div className="flex-1 min-w-0">
              <div className="text-sm font-semibold text-gray-800 truncate">{p.name}</div>
              <div className="text-xs text-gray-400 truncate">{p.role}{p.dept ? ` · ${p.dept}` : ''}</div>
            </div>
            {/* Status select */}
            <select value={p.status} onChange={e => updateStatus(p.id, e.target.value)}
              className="text-xs border border-gray-200 rounded-lg px-2 py-1.5 bg-white cursor-pointer outline-none focus:border-blue-400 flex-shrink-0">
              {['present','absent','late','excused'].map(s => (
                <option key={s} value={s}>{s.charAt(0).toUpperCase()+s.slice(1)}</option>
              ))}
            </select>
            {/* Badge */}
            <span className={`text-xs font-semibold px-2 py-0.5 rounded-full flex-shrink-0 ${badge[p.status]}`}>
              {p.status}
            </span>
            {/* Edit / Delete */}
            <div className="flex gap-1 flex-shrink-0 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => openEdit(p)}
                className="w-7 h-7 flex items-center justify-center rounded-lg bg-blue-50 hover:bg-blue-100 text-blue-600 text-xs transition-colors" title="Edit">✏️</button>
              <button onClick={() => setConfirmDelete(p.id)}
                className="w-7 h-7 flex items-center justify-center rounded-lg bg-red-50 hover:bg-red-100 text-red-500 text-xs transition-colors" title="Delete">🗑️</button>
            </div>
          </div>
        ))}
      </div>

      {/* Action buttons */}
      <div className="flex flex-wrap gap-2">
        <button onClick={openAdd}
          className="flex items-center gap-1.5 px-4 py-2 bg-blue-600 text-white rounded-xl text-sm font-medium hover:bg-blue-700 transition-colors">
          ➕ Add Member
        </button>
        <button onClick={exportPDF} disabled={pdfLoading}
          className="flex items-center gap-1.5 px-4 py-2 bg-green-600 text-white rounded-xl text-sm font-medium hover:bg-green-700 transition-colors disabled:opacity-60 disabled:cursor-not-allowed">
          {pdfLoading ? '⏳ Generating...' : '📄 Export PDF'}
        </button>
        <button onClick={() => {
          const csv = ['Name,Role,Department,Status', ...records.map(r => `"${r.name}","${r.role}","${r.dept||''}","${r.status}"`)].join('\n');
          const blob = new Blob([csv], { type: 'text/csv' });
          const url = URL.createObjectURL(blob);
          const a = document.createElement('a'); a.href = url;
          a.download = `LASU_Attendance_${new Date().toISOString().split('T')[0]}.csv`;
          a.click(); URL.revokeObjectURL(url);
        }} className="flex items-center gap-1.5 px-4 py-2 bg-gray-100 text-gray-700 rounded-xl text-sm font-medium hover:bg-gray-200 transition-colors">
          📊 Export CSV
        </button>
      </div>

      {exportMsg && (
        <div className={`mt-3 px-4 py-2.5 rounded-xl text-sm font-medium ${exportMsg.startsWith('✅') ? 'bg-green-50 text-green-700 border border-green-200' : 'bg-red-50 text-red-700 border border-red-200'}`}>
          {exportMsg}
        </div>
      )}

      {/* Add / Edit Form Modal */}
      {showForm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4" style={{ background: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(6px)' }}
          onClick={e => { if (e.target === e.currentTarget) setShowForm(false); }}>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm p-6 animate-bounce-in">
            <h3 className="text-lg font-bold text-gray-900 mb-5">{editingId ? '✏️ Edit Member' : '➕ Add New Member'}</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Full Name *</label>
                <input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                  placeholder="e.g. Prof. Adeyemi Okon"
                  className={`w-full px-3 py-2.5 border rounded-xl text-sm outline-none focus:border-blue-400 ${formErrors.name ? 'border-red-400 bg-red-50' : 'border-gray-200'}`} />
                {formErrors.name && <p className="text-red-500 text-xs mt-1">{formErrors.name}</p>}
              </div>

              <div>
                <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Role / Title *</label>
                <input value={form.role} onChange={e => setForm(f => ({ ...f, role: e.target.value }))}
                  placeholder="e.g. Vice Chancellor"
                  className={`w-full px-3 py-2.5 border rounded-xl text-sm outline-none focus:border-blue-400 ${formErrors.role ? 'border-red-400 bg-red-50' : 'border-gray-200'}`} />
                {formErrors.role && <p className="text-red-500 text-xs mt-1">{formErrors.role}</p>}
              </div>

              <div>
                <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Department / Faculty</label>
                <input value={form.dept} onChange={e => setForm(f => ({ ...f, dept: e.target.value }))}
                  placeholder="e.g. Faculty of Science"
                  className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm outline-none focus:border-blue-400" />
              </div>

              <div>
                <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Attendance Status</label>
                <div className="grid grid-cols-2 gap-2">
                  {['present','absent','late','excused'].map(s => (
                    <button key={s} onClick={() => setForm(f => ({ ...f, status: s }))}
                      className={`py-2 rounded-xl text-sm font-medium border transition-all ${
                        form.status === s
                          ? s === 'present' ? 'bg-green-600 text-white border-green-600'
                          : s === 'absent'  ? 'bg-red-600 text-white border-red-600'
                          : s === 'late'    ? 'bg-yellow-500 text-white border-yellow-500'
                          : 'bg-blue-600 text-white border-blue-600'
                          : 'bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100'
                      }`}>
                      {s.charAt(0).toUpperCase()+s.slice(1)}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="flex gap-3 mt-6">
              <button onClick={saveForm}
                className="flex-1 py-2.5 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 transition-colors">
                {editingId ? 'Save Changes' : 'Add Member'}
              </button>
              <button onClick={() => setShowForm(false)}
                className="px-5 py-2.5 bg-gray-100 text-gray-600 rounded-xl text-sm font-medium hover:bg-gray-200 transition-colors">
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Confirm Delete Modal */}
      {confirmDelete && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4" style={{ background: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(6px)' }}>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-xs p-6 text-center">
            <div className="text-4xl mb-3">🗑️</div>
            <h3 className="font-bold text-gray-900 text-base mb-2">Remove Member?</h3>
            <p className="text-sm text-gray-500 mb-5">This member will be removed from the attendance register. This cannot be undone.</p>
            <div className="flex gap-3">
              <button onClick={() => deleteRecord(confirmDelete)}
                className="flex-1 py-2.5 bg-red-600 text-white rounded-xl text-sm font-semibold hover:bg-red-700 transition-colors">
                Yes, Remove
              </button>
              <button onClick={() => setConfirmDelete(null)}
                className="flex-1 py-2.5 bg-gray-100 text-gray-600 rounded-xl text-sm font-medium hover:bg-gray-200 transition-colors">
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function SchedulePanel() {
  const store = window.__lasuStore || {};
  const allMeetings = store.meetingHistory || [];
  const meetings = allMeetings.filter(m => isUpcoming(m.date));
  const [tick, setTick]       = useState(0);
  const [search, setSearch]   = useState('');
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    const id = setInterval(() => setTick(t => t + 1), 60000);
    return () => clearInterval(id);
  }, []);

  const getCountdown = (dateStr, timeStr) => {
    const [y, mo, d] = dateStr.split('-').map(Number);
    let h = 0, min = 0;
    if (timeStr) {
      const isPM = /pm/i.test(timeStr);
      const isAM = /am/i.test(timeStr);
      const cleaned = timeStr.replace(/[apm\s]/gi, '');
      const parts = cleaned.split(':').map(Number);
      h = parts[0] || 0;
      min = parts[1] || 0;
      if (isPM && h !== 12) h += 12;
      if (isAM && h === 12) h = 0;
    }
    const target = new Date(y, mo - 1, d, h, min);
    const diff = target - new Date();
    if (diff <= 0) return null;
    const days = Math.floor(diff / 86400000);
    const hrs  = Math.floor((diff % 86400000) / 3600000);
    const mins = Math.floor((diff % 3600000) / 60000);
    if (days > 0) return `in ${days}d ${hrs}h`;
    if (hrs  > 0) return `in ${hrs}h ${mins}m`;
    return `in ${mins}m`;
  };

  // Stats
  const todayMeetings   = meetings.filter(m => new Date(m.date).toDateString() === new Date().toDateString());
  const thisWeek = meetings.filter(m => {
    const diff = (new Date(m.date) - new Date()) / 86400000;
    return diff >= 0 && diff < 7;
  });
  const withLink  = meetings.filter(m => m.link);
  const totalInvitees = [...new Set(meetings.flatMap(m => m.invitees || []))].length;

  let filtered = [...meetings];
  if (search.trim()) {
    const q = search.toLowerCase();
    filtered = filtered.filter(m =>
      m.title.toLowerCase().includes(q) ||
      (m.invitees || []).some(i => i.toLowerCase().includes(q)) ||
      (m.agenda || []).some(a => a.toLowerCase().includes(q))
    );
  }
  filtered.sort((a, b) => new Date(a.date) - new Date(b.date) || a.time.localeCompare(b.time));

  const grouped = filtered.reduce((acc, m) => {
    const key = new Date(m.date).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
    if (!acc[key]) acc[key] = [];
    acc[key].push(m);
    return acc;
  }, {});
  const sortedKeys = Object.keys(grouped).sort((a, b) => new Date(a) - new Date(b));

  /* ── Detail Modal ── */
  if (selected) {
    const m = selected;
    const meetDate = new Date(m.date).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
    const countdown = getCountdown(m.date, m.time);
    const isToday   = new Date(m.date).toDateString() === new Date().toDateString();
    return (
      <div>
        <button onClick={() => setSelected(null)}
          className="mb-4 text-sm text-orange-600 hover:text-orange-800 flex items-center gap-1 font-medium">
          ← Back to Schedule
        </button>
        <div className="bg-gradient-to-br from-orange-50 to-amber-50 border border-orange-200 rounded-2xl p-5 space-y-4">
          {/* Title bar */}
          <div className="flex items-start justify-between gap-3">
            <div>
              <h2 className="text-lg font-bold text-gray-800">{m.title}</h2>
              <p className="text-sm text-gray-500 mt-0.5">{meetDate} at {m.time}</p>
            </div>
            <div className="flex flex-col items-end gap-1">
              {isToday && <span className="text-xs bg-orange-500 text-white font-bold px-2.5 py-1 rounded-full">Today</span>}
              {countdown && <span className="text-xs bg-orange-100 text-orange-700 font-bold px-2 py-0.5 rounded-full">{countdown}</span>}
            </div>
          </div>

          {/* Info row */}
          <div className="grid grid-cols-3 gap-2">
            <div className="bg-white rounded-xl px-3 py-2.5 border border-orange-100 text-center">
              <p className="text-xs text-gray-400 mb-0.5">Date</p>
              <p className="text-xs font-bold text-gray-700">{new Date(m.date).toLocaleDateString('en-US', {month:'short', day:'numeric', year:'numeric'})}</p>
            </div>
            <div className="bg-white rounded-xl px-3 py-2.5 border border-orange-100 text-center">
              <p className="text-xs text-gray-400 mb-0.5">Time</p>
              <p className="text-sm font-bold text-orange-600">{m.time}</p>
            </div>
            <div className="bg-white rounded-xl px-3 py-2.5 border border-orange-100 text-center">
              <p className="text-xs text-gray-400 mb-0.5">Invitees</p>
              <p className="text-sm font-bold text-gray-700">{m.invitees?.length || 0}</p>
            </div>
          </div>

          {/* Meeting link */}
          {m.link && (
            <div className="bg-blue-50 border border-blue-100 rounded-xl px-4 py-3">
              <p className="text-xs text-blue-400 font-semibold mb-1">🔗 Meeting Link</p>
              <a href={m.link} target="_blank" rel="noopener noreferrer"
                className="text-sm text-blue-600 hover:underline break-all">{m.link}</a>
            </div>
          )}

          {/* Invitees */}
          {m.invitees?.length > 0 && (
            <div className="bg-white border border-gray-200 rounded-xl px-4 py-3">
              <p className="text-xs text-gray-400 font-semibold mb-2">👥 Invitees ({m.invitees.length})</p>
              <div className="flex flex-wrap gap-1.5">
                {m.invitees.map((email, i) => (
                  <span key={i} className="text-xs bg-orange-100 text-orange-700 px-2.5 py-1 rounded-full">{email}</span>
                ))}
              </div>
            </div>
          )}

          {/* Agenda */}
          {m.agenda?.length > 0 && (
            <div className="bg-white border border-gray-200 rounded-xl px-4 py-3">
              <p className="text-xs text-gray-400 font-semibold mb-2">📋 Agenda ({m.agenda.length} items)</p>
              <ol className="space-y-1.5">
                {m.agenda.map((item, i) => (
                  <li key={i} className="flex gap-2 text-sm text-gray-700">
                    <span className="flex-shrink-0 w-5 h-5 rounded-full bg-orange-100 text-orange-600 text-xs font-bold flex items-center justify-center mt-0.5">{i+1}</span>
                    <span>{item}</span>
                  </li>
                ))}
              </ol>
            </div>
          )}

          {!m.agenda?.length && !m.invitees?.length && !m.link && (
            <p className="text-sm text-gray-400 italic text-center py-2">No additional details recorded.</p>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-5">
      {/* Summary stats */}
      <div className="grid grid-cols-4 gap-2">
        {[
          ['📅', 'Total', meetings.length, 'orange'],
          ['🌅', 'Today', todayMeetings.length, 'yellow'],
          ['📆', 'This Week', thisWeek.length, 'blue'],
          ['👥', 'Invitees', totalInvitees, 'purple'],
        ].map(([icon, label, val, color]) => (
          <div key={label} className={`text-center py-2.5 rounded-xl bg-${color}-50 border border-${color}-200`}>
            <div className="text-base mb-0.5">{icon}</div>
            <div className={`text-lg font-bold text-${color}-600`}>{val}</div>
            <div className="text-xs text-gray-500">{label}</div>
          </div>
        ))}
      </div>

      {/* Search bar */}
      {meetings.length > 0 && (
        <input value={search} onChange={e => setSearch(e.target.value)}
          placeholder="🔍 Search upcoming meetings..."
          className="w-full px-4 py-2 border border-gray-200 rounded-xl text-sm outline-none focus:border-orange-400" />
      )}

      {meetings.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-16 text-center">
          <div className="text-5xl mb-4">📅</div>
          <p className="text-gray-500 font-medium">No upcoming meetings</p>
          <p className="text-gray-400 text-sm mt-1">Schedule a meeting from the Meeting Hub to see it here.</p>
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-8 text-gray-400 text-sm">No results for "{search}"</div>
      ) : (
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <p className="text-xs text-gray-400 uppercase tracking-wider font-semibold">Upcoming Meetings</p>
            <span className="text-xs bg-orange-100 text-orange-600 font-bold px-2.5 py-1 rounded-full">{filtered.length} scheduled</span>
          </div>
          {sortedKeys.map(dateKey => (
            <div key={dateKey}>
              <div className="flex items-center gap-2 mb-3">
                <div className="h-px flex-1 bg-gray-100" />
                <span className="text-xs font-semibold text-gray-400 uppercase tracking-wider px-2">{dateKey}</span>
                <div className="h-px flex-1 bg-gray-100" />
              </div>
              <div className="space-y-2">
                {grouped[dateKey].map(m => {
                  const countdown = getCountdown(m.date, m.time);
                  const isToday = new Date(m.date).toDateString() === new Date().toDateString();
                  const isTomorrow = (() => { const t = new Date(); t.setDate(t.getDate()+1); return new Date(m.date).toDateString() === t.toDateString(); })();
                  return (
                    <div key={m.id}
                      onClick={() => setSelected(m)}
                      className={`flex items-start gap-4 px-4 py-3.5 rounded-xl border cursor-pointer transition-all hover:shadow-md group
                        ${isToday ? 'bg-orange-50 border-orange-200 hover:border-orange-400' : 'bg-white border-gray-200 hover:border-orange-300 hover:bg-orange-50/30'}`}>
                      {/* Time column */}
                      <div className="flex-shrink-0 w-16 text-center">
                        <div className={`text-sm font-bold font-mono ${isToday ? 'text-orange-600' : 'text-blue-600'}`}>{m.time}</div>
                        {isToday && <div className="text-xs text-orange-400 font-medium mt-0.5">Today</div>}
                        {isTomorrow && <div className="text-xs text-purple-400 font-medium mt-0.5">Tomorrow</div>}
                      </div>
                      {/* Details */}
                      <div className="flex-1 min-w-0">
                        <div className="font-semibold text-gray-800 text-sm group-hover:text-orange-700 transition-colors truncate">{m.title}</div>
                        <div className="flex flex-wrap items-center gap-2 mt-1">
                          {m.invitees?.length > 0 && <span className="text-xs text-gray-400">👥 {m.invitees.length} invitee{m.invitees.length !== 1 ? 's' : ''}</span>}
                          {m.agenda?.length > 0 && <span className="text-xs text-gray-400">📋 {m.agenda.length} item{m.agenda.length !== 1 ? 's' : ''}</span>}
                          {m.link && <span className="text-xs text-blue-400">🔗 Virtual</span>}
                        </div>
                      </div>
                      {/* Countdown */}
                      <div className="flex-shrink-0 flex flex-col items-end gap-1">
                        {countdown && <span className="text-xs bg-gray-100 text-gray-500 font-mono px-2 py-0.5 rounded-full">{countdown}</span>}
                        <span className="text-gray-300 text-sm group-hover:text-orange-400 transition-colors">›</span>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

