function ArchivesPanel() {
  const store = window.__lasuStore || {};
  const allMeetings  = store.meetingHistory || [];
  const past         = allMeetings.filter(m => !isUpcoming(m.date));

  const [q, setQ]           = useState('');
  const [sortBy, setSortBy] = useState('date-desc');
  const [expanded, setExpanded] = useState(null);
  const [pdfLoading, setPdfLoading] = useState(false);
  const [exportMsg, setExportMsg]   = useState('');

  let list = [...past];
  if (q.trim()) {
    const lq = q.toLowerCase();
    list = list.filter(m =>
      m.title.toLowerCase().includes(lq) ||
      (m.invitees || []).some(i => i.toLowerCase().includes(lq)) ||
      (m.agenda || []).some(a => a.toLowerCase().includes(lq))
    );
  }
  list.sort((a, b) => {
    if (sortBy === 'date-asc')  return new Date(a.date) - new Date(b.date);
    if (sortBy === 'title')     return a.title.localeCompare(b.title);
    return new Date(b.date) - new Date(a.date);
  });

  // ── Stats ──────────────────────────────────────────────────────────────────
  const totalInvitees  = [...new Set(past.flatMap(m => m.invitees || []))].length;
  const totalAgendaItems = past.reduce((s, m) => s + (m.agenda?.length || 0), 0);
  const withLink       = past.filter(m => m.link).length;

  // ── PDF export ─────────────────────────────────────────────────────────────
  const exportPDF = (m) => {
    setPdfLoading(true);
    const meetDate = new Date(m.date).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
    const inviteesHtml = m.invitees?.length
      ? m.invitees.map(e => `<span class="tag">${e}</span>`).join('')
      : '<em style="color:#9ca3af">No invitees recorded</em>';
    const agendaHtml = m.agenda?.length
      ? m.agenda.map((item, i) => `<li><span class="num">${i+1}</span><span>${item}</span></li>`).join('')
      : '<li style="color:#9ca3af"><em>No agenda items recorded</em></li>';
    const linkHtml = m.link
      ? `<div class="section"><p class="label">🔗 Meeting Link</p><a href="${m.link}" class="link">${m.link}</a></div>`
      : '';
    const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
<title>Meeting Archive – ${m.title}</title>
<style>
  @page { margin:2cm 2.5cm; }
  body { font-family:'Segoe UI',Arial,sans-serif; color:#1f2937; margin:0; padding:0; font-size:13px; }
  .header { display:flex; align-items:center; gap:16px; border-bottom:3px solid #16a34a; padding-bottom:14px; margin-bottom:20px; }
  .header img { width:64px; height:64px; object-fit:contain; }
  .header-text h1 { margin:0; font-size:18px; color:#15803d; font-weight:800; }
  .header-text p  { margin:2px 0 0; font-size:11px; color:#6b7280; }
  .badge { display:inline-block; background:#dcfce7; color:#166534; border:1px solid #86efac; border-radius:20px; padding:2px 10px; font-size:11px; font-weight:700; }
  .title-row { display:flex; align-items:flex-start; justify-content:space-between; margin-bottom:16px; }
  .title-row h2 { margin:0; font-size:22px; color:#1f2937; font-weight:800; }
  .meta { display:flex; gap:10px; flex-wrap:wrap; margin-bottom:18px; }
  .meta-box { flex:1; min-width:120px; background:#f9fafb; border:1px solid #e5e7eb; border-radius:8px; padding:8px 12px; }
  .meta-box .lbl { font-size:10px; color:#9ca3af; text-transform:uppercase; letter-spacing:.5px; }
  .meta-box .val { font-size:13px; font-weight:700; color:#111827; margin-top:2px; }
  .section { background:#f9fafb; border:1px solid #e5e7eb; border-radius:8px; padding:12px 16px; margin-bottom:12px; }
  .label { font-size:10px; color:#6b7280; text-transform:uppercase; letter-spacing:.5px; font-weight:700; margin:0 0 8px; }
  .tags { display:flex; flex-wrap:wrap; gap:6px; }
  .tag { background:#dbeafe; color:#1d4ed8; border-radius:20px; padding:3px 10px; font-size:11px; font-weight:600; }
  ol.agenda { margin:0; padding:0; list-style:none; }
  ol.agenda li { display:flex; gap:10px; padding:6px 0; border-bottom:1px solid #f3f4f6; align-items:flex-start; }
  ol.agenda li:last-child { border:none; }
  .num { width:20px; height:20px; border-radius:50%; background:#fef3c7; color:#d97706; font-size:11px; font-weight:800; display:flex; align-items:center; justify-content:center; flex-shrink:0; }
  .link { color:#2563eb; font-size:12px; word-break:break-all; }
  .footer { text-align:center; font-size:10px; color:#9ca3af; margin-top:24px; border-top:1px solid #e5e7eb; padding-top:10px; }
</style></head><body>
<div class="header">
  <img id="lasu-logo-archive" src="" alt="LASU Logo" />
  <div class="header-text">
    <h1>Lagos State University</h1>
    <p>Boardroom Interactive Suite – Meeting Archive</p>
  </div>
</div>
<div class="title-row">
  <h2>${m.title}</h2>
  <span class="badge">✓ Completed</span>
</div>
<div class="meta">
  <div class="meta-box"><div class="lbl">Date</div><div class="val">${meetDate}</div></div>
  <div class="meta-box"><div class="lbl">Time</div><div class="val">${m.time}</div></div>
  <div class="meta-box"><div class="lbl">Invitees</div><div class="val">${m.invitees?.length || 0}</div></div>
  <div class="meta-box"><div class="lbl">Agenda Items</div><div class="val">${m.agenda?.length || 0}</div></div>
</div>
${linkHtml}
<div class="section">
  <p class="label">👥 Invitees</p>
  <div class="tags">${inviteesHtml}</div>
</div>
<div class="section">
  <p class="label">📋 Agenda</p>
  <ol class="agenda">${agendaHtml}</ol>
</div>
<div class="footer">This document was generated by the LASU Boardroom Interactive Suite &nbsp;•&nbsp; Confidential</div>
<script>window.onload=function(){setTimeout(function(){window.print();},400);};</script>
</body></html>`;

    const win = window.open('', '_blank', 'width=900,height=700');
    if (!win) {
      setExportMsg('❌ Pop-up blocked! Allow pop-ups for this site and try again.');
      setTimeout(() => setExportMsg(''), 5000);
      setPdfLoading(false);
      return;
    }
    win.document.write(html);
    win.document.close();
    try {
      const logoEl = win.document.getElementById('lasu-logo-archive');
      if (logoEl) logoEl.src = (window.__lasuStore || {}).LASU_LOGO_B64 || '';
    } catch(e) {}
    setExportMsg('✅ Print dialog opened — choose "Save as PDF"');
    setTimeout(() => setExportMsg(''), 5000);
    setPdfLoading(false);
  };

  if (past.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-16 text-center">
        <div className="text-5xl mb-4">📁</div>
        <p className="text-gray-500 font-medium">No archived meetings yet</p>
        <p className="text-gray-400 text-sm mt-1">Past meetings will appear here automatically after they are completed.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Stats */}
      <div className="grid grid-cols-4 gap-2">
        {[
          ['📁', 'Total', past.length, 'red'],
          ['👥', 'Invitees', totalInvitees, 'blue'],
          ['📋', 'Agenda Items', totalAgendaItems, 'green'],
          ['🔗', 'Virtual', withLink, 'purple'],
        ].map(([icon, label, val, color]) => (
          <div key={label} className={`text-center py-2.5 rounded-xl bg-${color}-50 border border-${color}-200`}>
            <div className="text-base mb-0.5">{icon}</div>
            <div className={`text-lg font-bold text-${color}-600`}>{val}</div>
            <div className="text-xs text-gray-500">{label}</div>
          </div>
        ))}
      </div>

      {/* Export message */}
      {exportMsg && (
        <div className={`text-center text-xs py-2 px-3 rounded-lg font-medium ${exportMsg.startsWith('✅') ? 'bg-green-50 text-green-700 border border-green-200' : 'bg-red-50 text-red-700 border border-red-200'}`}>
          {exportMsg}
        </div>
      )}

      {/* Search + sort */}
      <div className="flex gap-2">
        <input value={q} onChange={e => setQ(e.target.value)} placeholder="🔍 Search archives..."
          className="flex-1 px-4 py-2 border border-gray-200 rounded-xl text-sm outline-none focus:border-red-400" />
        <select value={sortBy} onChange={e => setSortBy(e.target.value)}
          className="px-3 py-2 border border-gray-200 rounded-xl text-xs text-gray-600 outline-none focus:border-red-400 bg-white">
          <option value="date-desc">Newest First</option>
          <option value="date-asc">Oldest First</option>
          <option value="title">A–Z</option>
        </select>
      </div>

      <div className="flex items-center justify-between">
        <p className="text-xs text-gray-400 uppercase tracking-wider font-semibold">Past Meetings</p>
        <span className="text-xs bg-red-100 text-red-600 font-bold px-2.5 py-1 rounded-full">{past.length} archived</span>
      </div>

      {list.length === 0 && (
        <div className="text-center py-8 text-gray-400 text-sm">No results for "{q}"</div>
      )}

      <div className="space-y-2">
        {list.map(m => {
          const isOpen  = expanded === m.id;
          const meetDate = new Date(m.date).toLocaleDateString('en-US', { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' });
          return (
            <div key={m.id} className={`border rounded-xl overflow-hidden transition-all ${isOpen ? 'border-red-300 shadow-md' : 'border-gray-200 hover:border-gray-300'}`}>
              {/* ── Header row ── */}
              <button onClick={() => setExpanded(isOpen ? null : m.id)}
                className="w-full flex items-center gap-4 px-4 py-3.5 text-left bg-white hover:bg-gray-50 transition-colors">
                <div className="flex-shrink-0">
                  <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-red-400 to-red-600 flex items-center justify-center text-white text-lg">📁</div>
                </div>
                <div className="flex-1 min-w-0">
                  <div className="font-semibold text-gray-800 text-sm truncate">{m.title}</div>
                  <div className="text-xs text-gray-400 mt-0.5 flex items-center gap-3">
                    <span>📅 {meetDate}</span>
                    <span>⏰ {m.time}</span>
                    {m.invitees?.length > 0 && <span>👥 {m.invitees.length}</span>}
                    {m.agenda?.length > 0 && <span>📋 {m.agenda.length}</span>}
                  </div>
                </div>
                <div className="flex-shrink-0 flex items-center gap-2">
                  <span className="text-xs bg-green-100 text-green-600 px-2 py-0.5 rounded-full font-medium">✓ Completed</span>
                  <span className={`text-gray-400 text-sm transition-transform ${isOpen ? 'rotate-180' : ''}`}>▾</span>
                </div>
              </button>

              {/* ── Expanded detail ── */}
              {isOpen && (
                <div className="px-4 pb-4 pt-3 bg-gray-50 border-t border-gray-100 space-y-3">
                  {/* Meta boxes */}
                  <div className="grid grid-cols-3 gap-2">
                    <div className="bg-white rounded-xl px-3 py-2.5 border border-gray-200">
                      <p className="text-xs text-gray-400 mb-0.5">Date</p>
                      <p className="text-xs font-bold text-gray-700">{meetDate}</p>
                    </div>
                    <div className="bg-white rounded-xl px-3 py-2.5 border border-gray-200">
                      <p className="text-xs text-gray-400 mb-0.5">Time</p>
                      <p className="text-sm font-bold text-red-600">{m.time}</p>
                    </div>
                    <div className="bg-white rounded-xl px-3 py-2.5 border border-gray-200">
                      <p className="text-xs text-gray-400 mb-0.5">Scheduled</p>
                      <p className="text-xs font-semibold text-gray-600">{new Date(m.createdAt).toLocaleDateString()}</p>
                    </div>
                  </div>

                  {/* Meeting link */}
                  {m.link && (
                    <div className="bg-blue-50 border border-blue-100 rounded-xl px-4 py-3">
                      <p className="text-xs text-blue-400 font-semibold mb-1">🔗 Meeting Link</p>
                      <a href={m.link} target="_blank" rel="noopener noreferrer"
                        className="text-sm text-blue-600 hover:underline break-all">{m.link}</a>
                    </div>
                  )}

                  {/* Invitees */}
                  {m.invitees?.length > 0 && (
                    <div className="bg-white border border-gray-200 rounded-xl px-4 py-3">
                      <p className="text-xs text-gray-400 font-semibold mb-2">👥 Invitees ({m.invitees.length})</p>
                      <div className="flex flex-wrap gap-1.5">
                        {m.invitees.map((email, i) => (
                          <span key={i} className="text-xs bg-blue-100 text-blue-700 px-2.5 py-1 rounded-full">{email}</span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Agenda */}
                  {m.agenda?.length > 0 && (
                    <div className="bg-white border border-gray-200 rounded-xl px-4 py-3">
                      <p className="text-xs text-gray-400 font-semibold mb-2">📋 Agenda ({m.agenda.length} items)</p>
                      <ol className="space-y-1.5">
                        {m.agenda.map((item, i) => (
                          <li key={i} className="flex gap-2 text-sm text-gray-700">
                            <span className="flex-shrink-0 w-5 h-5 rounded-full bg-red-100 text-red-600 text-xs font-bold flex items-center justify-center mt-0.5">{i+1}</span>
                            <span>{item}</span>
                          </li>
                        ))}
                      </ol>
                    </div>
                  )}

                  {!m.agenda?.length && !m.invitees?.length && !m.link && (
                    <p className="text-sm text-gray-400 italic text-center py-2">No additional details were recorded for this meeting.</p>
                  )}

                  {/* Actions */}
                  <div className="flex gap-2 pt-1">
                    <button
                      onClick={() => exportPDF(m)}
                      disabled={pdfLoading}
                      className="flex-1 py-2 bg-red-600 hover:bg-red-700 text-white text-xs font-bold rounded-lg transition-colors disabled:opacity-60">
                      {pdfLoading ? '⏳ Generating…' : '🖨️ Export as PDF'}
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

function MailPanel() {
  const [selected, setSelected] = useState(null);
  const COLORS = ['#3b82f6','#a855f7','#ec4899','#f97316','#14b8a6'];
  if (selected !== null) {
    const m = MAILS_DATA[selected];
    return (
      <div>
        <button onClick={() => setSelected(null)} className="mb-4 text-sm text-blue-600 hover:text-blue-800 flex items-center gap-1">← Back to Inbox</button>
        <div className="bg-gray-50 border border-gray-200 rounded-xl p-5">
          <div className="font-bold text-gray-900 text-base mb-1">{m.subject}</div>
          <div className="text-xs text-gray-400 mb-4">From: {m.from} · {m.date}</div>
          <hr className="mb-4" />
          <div className="text-sm text-gray-600 leading-relaxed">
            Dear recipient,<br/><br/>
            This is a sample email body for <strong>"{m.subject}"</strong>. In production, emails are fetched from the institution's mail server via IMAP/SMTP integration.<br/><br/>
            Best regards,<br/>{m.from}
          </div>
        </div>
        <div className="flex gap-2 mt-4">
          <button className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700" onClick={() => alert('Reply drafted!')}>↩ Reply</button>
          <button className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg text-sm font-medium hover:bg-gray-200" onClick={() => alert('Forwarded!')}>⇒ Forward</button>
        </div>
      </div>
    );
  }
  return (
    <div>
      <button className="mb-4 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700" onClick={() => alert('Compose — connect to mail server')}>✏️ Compose</button>
      {MAILS_DATA.map((m, i) => (
        <div key={i} onClick={() => setSelected(i)} className="flex items-start gap-3 py-3 border-b border-gray-100 cursor-pointer hover:bg-gray-50 rounded-lg px-1 transition-colors last:border-0">
          <div className="w-9 h-9 rounded-full flex-shrink-0 flex items-center justify-center text-white text-sm font-bold" style={{ background: COLORS[i % COLORS.length] }}>{initials(m.from)}</div>
          <div className="flex-1 min-w-0">
            <div className={`text-sm ${m.unread ? 'font-bold text-blue-700' : 'font-medium text-gray-700'}`}>{m.from} {m.unread && <span className="text-blue-500 text-xs">●</span>}</div>
            <div className="text-xs text-gray-400 truncate">{m.subject}</div>
          </div>
          <div className="text-xs text-gray-400 flex-shrink-0">{m.date}</div>
        </div>
      ))}
    </div>
  );
}

