function SettingsPanel({ isDarkMode = false, setIsDarkMode = () => {} }) {
  // Load settings from localStorage with error handling
  const [toggles, setToggles] = useState(() => {
    try {
      return {
        dark: isDarkMode,
        clock24: loadFromStorage('clock24', true),
        notifs: loadFromStorage('notifs', true),
        autolock: loadFromStorage('autolock', false),
        sounds: loadFromStorage('sounds', true)
      };
    } catch (error) {
      console.error('Error loading settings:', error);
      return {
        dark: isDarkMode,
        clock24: true,
        notifs: true,
        autolock: false,
        sounds: true
      };
    }
  });
  
  const [name, setName] = useState(() => {
    try {
      return loadFromStorage('institutionName', 'Lagos State University');
    } catch (error) {
      console.error('Error loading institution name:', error);
      return 'Lagos State University';
    }
  });
  
  const [saved, setSaved] = useState(false);
  
  // Update toggles when isDarkMode changes from parent
  useEffect(() => {
    setToggles(t => ({ ...t, dark: isDarkMode }));
  }, [isDarkMode]);
  
  const toggle = k => {
    const newValue = !toggles[k];
    setToggles(t => ({ ...t, [k]: newValue }));
    
    // Special handling for dark mode - update parent state
    if (k === 'dark') {
      setIsDarkMode(newValue);
    } else {
      // Save other settings to localStorage immediately
      try {
        localStorage.setItem(k, JSON.stringify(newValue));
      } catch (error) {
        console.error('Error saving setting:', error);
      }
    }
  };
  
  const handleSaveSettings = () => {
    try {
      // Save all settings to localStorage
      localStorage.setItem('clock24', JSON.stringify(toggles.clock24));
      localStorage.setItem('notifs', JSON.stringify(toggles.notifs));
      localStorage.setItem('autolock', JSON.stringify(toggles.autolock));
      localStorage.setItem('sounds', JSON.stringify(toggles.sounds));
      localStorage.setItem('institutionName', name);
      
      // Trigger a custom event to update clock format immediately
      window.dispatchEvent(new Event('clockFormatChanged'));
      
      // Show saved confirmation
      setSaved(true);
      setTimeout(() => setSaved(false), 2000);
    } catch (error) {
      console.error('Error saving settings:', error);
      alert('Failed to save settings. Please try again.');
    }
  };
  
  const Toggle = ({ k }) => (
    <button onClick={() => toggle(k)} className={`w-11 h-6 rounded-full transition-all relative flex-shrink-0 ${toggles[k] ? 'bg-blue-600' : 'bg-gray-200'}`}>
      <div className={`absolute top-0.5 w-5 h-5 rounded-full bg-white shadow transition-all ${toggles[k] ? 'left-5' : 'left-0.5'}`} />
    </button>
  );
  
  const Row = ({ label, sub, k, children }) => (
    <div className="flex items-center justify-between py-4 border-b border-gray-100 last:border-0">
      <div>
        <div className="text-sm font-medium text-gray-800">{label}</div>
        {sub && <div className="text-xs text-gray-400 mt-0.5">{sub}</div>}
      </div>
      {k ? <Toggle k={k} /> : children}
    </div>
  );
  
  return (
    <div>
      <Row label="Dark Mode" sub="Theme for boardroom displays" k="dark" />
      <Row label="24-Hour Clock" sub="Display time in 24-hour format" k="clock24" />
      <Row label="Notifications" sub="Show badge on apps with updates" k="notifs" />
      <Row label="Auto-Lock Screen" sub="Lock after 15 minutes of inactivity" k="autolock" />
      <Row label="Sound Effects" sub="UI interaction sounds" k="sounds" />
      <Row label="Institution Name" sub="Shown in the dashboard header">
        <input 
          value={name} 
          onChange={e => setName(e.target.value)} 
          className="text-sm border border-gray-200 rounded-lg px-3 py-1.5 text-gray-800 outline-none focus:border-blue-400 w-44 text-right" 
        />
      </Row>
      
      <button 
        className={`mt-5 px-5 py-2.5 rounded-xl text-sm font-medium transition-all ${
          saved 
            ? 'bg-green-600 text-white' 
            : 'bg-blue-600 text-white hover:bg-blue-700'
        }`} 
        onClick={handleSaveSettings}
      >
        {saved ? '✓ Settings Saved!' : '💾 Save Settings'}
      </button>
      
      {saved && (
        <p className="mt-2 text-xs text-green-600 font-medium">
          Your preferences have been saved successfully!
        </p>
      )}
    </div>
  );
}

