function DashModal({ app, onClose, isDarkMode, setIsDarkMode }) {
  const Panel = app ? PANEL_COMPONENTS[app.id] : null;
  useEffect(() => {
    const fn = e => { if (e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', fn);
    return () => window.removeEventListener('keydown', fn);
  }, [onClose]);

  return (
    <div
      onClick={e => { if (e.target === e.currentTarget) onClose(); }}
      className={`fixed inset-0 z-50 flex items-center justify-center p-4 transition-opacity duration-200 ${app ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}
      style={{ background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(8px)' }}
    >
      {app && (
        <div className={`bg-white rounded-2xl shadow-2xl w-full max-w-3xl max-h-[85vh] flex flex-col transition-transform duration-200 ${app ? 'scale-100' : 'scale-95'}`}>
          {/* header */}
          <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100 flex-shrink-0">
            <div className="flex items-center gap-3">
              <div className={`w-9 h-9 rounded-xl bg-gradient-to-br ${app.bg} flex items-center justify-center text-lg`}>{app.icon}</div>
              <span className="font-bold text-gray-900 text-lg">{app.label}</span>
            </div>
            <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-gray-100 text-gray-400 hover:text-gray-700 transition-colors text-lg">✕</button>
          </div>
          {/* body */}
          <div className="overflow-y-auto px-6 py-5 flex-1">
            {Panel && (
              app.id === 'settings' 
                ? <Panel isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />
                : <Panel />
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ── Main Dashboard Wrapper ───────────────────────────────────────────────────

export default function App() {
  const [screen, setScreen] = useState('home'); // 'home' | 'meetinghub'
  const [activeApp, setActiveApp] = useState(null);
  const [query, setQuery] = useState('');
  const [showSearch, setShowSearch] = useState(false);
  const [time, setTime] = useState(new Date());
  const [isDarkMode, setIsDarkMode] = useState(() => loadFromStorage('darkMode', false));
  const [use24Hour, setUse24Hour] = useState(() => loadFromStorage('clock24', true));

  useEffect(() => {
    const t = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(t);
  }, []);
  
  // Save dark mode preference
  useEffect(() => {
    localStorage.setItem('darkMode', JSON.stringify(isDarkMode));
  }, [isDarkMode]);
  
  // Listen for clock format changes
  useEffect(() => {
    const handleStorageChange = () => {
      setUse24Hour(loadFromStorage('clock24', true));
    };
    const handleClockChange = () => {
      setUse24Hour(loadFromStorage('clock24', true));
    };
    window.addEventListener('storage', handleStorageChange);
    window.addEventListener('clockFormatChanged', handleClockChange);
    return () => {
      window.removeEventListener('storage', handleStorageChange);
      window.removeEventListener('clockFormatChanged', handleClockChange);
    };
  }, []);
  
  // Convert to 12-hour format if needed
  const hour24 = time.getHours();
  const hour12 = hour24 % 12 || 12; // Convert 0 to 12
  const ampm = hour24 >= 12 ? 'PM' : 'AM';
  
  const hh = use24Hour 
    ? String(hour24).padStart(2, '0')
    : String(hour12).padStart(2, '0');
  const mm = String(time.getMinutes()).padStart(2, '0');
  const ss = String(time.getSeconds()).padStart(2, '0');
  const DAYS = ['SUNDAY','MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY'];
  const MONTHS = ['JAN','FEB','MAR','APR','MAY','JUN','JUL','AUG','SEP','OCT','NOV','DEC'];
  const dateStr = `${DAYS[time.getDay()]}, ${MONTHS[time.getMonth()]} ${time.getDate()} ${time.getFullYear()}`;

  const filtered = query ? LASU_APPS.filter(a => a.label.toLowerCase().includes(query.toLowerCase())) : LASU_APPS;

  const openApp = (app) => {
    if (app.id === 'meetinghub') { setScreen('meetinghub'); return; }
    setActiveApp(app);
  };

  if (screen === 'meetinghub') {
    return (
      <div className="relative">
        <button
          onClick={() => setScreen('home')}
          className="fixed top-4 left-4 z-50 flex items-center gap-2 px-4 py-2 bg-white shadow-lg rounded-xl text-sm font-semibold text-gray-700 border border-gray-200 hover:bg-gray-50 transition-colors"
          style={{ zIndex: 9999 }}
        >
          ← Dashboard
        </button>
        <MeetingHub />
      </div>
    );
  }

  return (
    <div className="min-h-screen relative overflow-x-hidden" style={{ background: '#0d1117' }}>
      {/* bg glow */}
      <div className="fixed inset-0 pointer-events-none" style={{ background: 'radial-gradient(ellipse 70% 50% at 50% -10%, rgba(79,158,255,.12) 0%, transparent 70%), radial-gradient(ellipse 40% 40% at 90% 90%, rgba(167,139,250,.07) 0%, transparent 60%)' }} />

      <div className="relative z-10 flex flex-col items-center min-h-screen px-6 pb-24 pt-7">

        {/* Top bar */}
        <div className="w-full max-w-2xl flex justify-between items-center mb-8">
          <div className="flex items-center gap-3">
            <img src="/lasu-logo.png" alt="LASU" className="w-10 h-10 rounded-full border-2 border-blue-400 shadow-lg object-cover" onError={e => { e.target.style.display='none'; }} />
            <div>
              <div className="text-white text-xs font-bold tracking-wider uppercase opacity-90">Lagos State University</div>
              <div className="text-blue-300 text-xs opacity-60">Boardroom Suite</div>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={() => openApp(LASU_APPS.find(a => a.id === 'notices'))}
              className="relative w-9 h-9 rounded-xl flex items-center justify-center text-gray-300 hover:text-white transition-colors" style={{ background: 'rgba(255,255,255,0.08)' }}>
              🔔
              <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border border-gray-900 animate-pulse" />
            </button>
            <button onClick={() => openApp(LASU_APPS.find(a => a.id === 'settings'))}
              className="w-9 h-9 rounded-xl flex items-center justify-center text-gray-300 hover:text-white transition-colors" style={{ background: 'rgba(255,255,255,0.08)' }}>
              ⚙️
            </button>
          </div>
        </div>

        {/* Clock */}
        <div className="text-center mb-9">
          <div className="font-mono text-white leading-none" style={{ fontSize: 'clamp(52px,10vw,88px)', fontWeight: 200, letterSpacing: '-0.02em', textShadow: '0 0 40px rgba(79,158,255,0.3)' }}>
            {hh}<span style={{ opacity: 0.35, animation: 'blink 1s step-start infinite' }}>:</span>{mm}
            <span style={{ fontSize: 'clamp(18px,3vw,28px)', opacity: 0.45, marginLeft: 8 }}>{ss}</span>
            {!use24Hour && (
              <span style={{ fontSize: 'clamp(16px,2.5vw,24px)', opacity: 0.6, marginLeft: 12, fontWeight: 600 }}>
                {ampm}
              </span>
            )}
          </div>
          <div className="text-gray-400 text-xs tracking-widest uppercase mt-2">{dateStr}</div>
        </div>

        {/* Search */}
        <div className="relative w-full max-w-lg mb-10">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-base pointer-events-none">🔍</span>
          <input
            value={query}
            onChange={e => { setQuery(e.target.value); setShowSearch(!!e.target.value); }}
            onFocus={() => query && setShowSearch(true)}
            onBlur={() => setTimeout(() => setShowSearch(false), 200)}
            placeholder="Search boardroom apps..."
            className="w-full pl-11 pr-4 py-3 rounded-2xl text-white text-sm outline-none transition-all"
            style={{ background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.12)' }}
          />
          {showSearch && query && (
            <div className="absolute top-full mt-2 left-0 right-0 rounded-2xl shadow-2xl overflow-hidden z-20" style={{ background: '#1c2436', border: '1px solid rgba(255,255,255,0.1)' }}>
              {filtered.length ? filtered.map(a => (
                <div key={a.id} onClick={() => { openApp(a); setQuery(''); setShowSearch(false); }}
                  className="flex items-center gap-3 px-4 py-3 cursor-pointer hover:bg-white/5 transition-colors">
                  <div className={`w-7 h-7 rounded-lg bg-gradient-to-br ${a.bg} flex items-center justify-center text-sm`}>{a.icon}</div>
                  <span className="text-sm text-gray-200 font-medium">{a.label}</span>
                </div>
              )) : <div className="px-4 py-3 text-sm text-gray-400">No apps found</div>}
            </div>
          )}
        </div>

        {/* Apps grid */}
        <div className="w-full max-w-2xl">
          <div className="text-gray-500 text-xs font-bold tracking-widest uppercase mb-4">Applications</div>
          <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-5">
            {(query ? filtered : LASU_APPS).map((a, i) => (
              <button
                key={a.id}
                onClick={() => openApp(a)}
                className="flex flex-col items-center gap-2.5 group"
                style={{ animation: `fadeUp 0.35s ${i * 40}ms ease both` }}
              >
                <div className={`w-16 h-16 sm:w-18 sm:h-18 rounded-2xl bg-gradient-to-br ${a.bg} flex items-center justify-center text-2xl relative shadow-lg group-hover:scale-110 group-hover:shadow-2xl transition-all duration-200`}>
                  <div className="absolute inset-0 rounded-2xl" style={{ background: 'linear-gradient(135deg,rgba(255,255,255,0.18) 0%,transparent 60%)' }} />
                  {a.icon}
                  {a.notif && <span className="absolute top-1.5 right-1.5 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-gray-900 animate-pulse" />}
                </div>
                <span className="text-xs text-gray-300 text-center leading-tight font-medium group-hover:text-white transition-colors">{a.label}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Status bar */}
      <div className="fixed bottom-0 left-0 right-0 z-30 flex justify-between items-center px-6 py-2.5 text-xs text-gray-500"
        style={{ background: 'rgba(13,17,23,0.9)', backdropFilter: 'blur(12px)', borderTop: '1px solid rgba(255,255,255,0.06)' }}>
        <span>📡 Network: <span className="text-green-400">Online</span></span>
        <span className="font-mono text-blue-400">
          {hh}:{mm}:{ss}
          {!use24Hour && <span className="ml-1">{ampm}</span>}
        </span>
        <span>📅 1st Semester · 2025/2026</span>
      </div>

      <DashModal app={activeApp} onClose={() => setActiveApp(null)} isDarkMode={isDarkMode} setIsDarkMode={setIsDarkMode} />

      <style>{`
        @keyframes fadeUp { from { opacity:0; transform:translateY(16px); } to { opacity:1; transform:translateY(0); } }
        @keyframes blink  { 0%,100% { opacity:0.35; } 50% { opacity:0.1; } }
      `}</style>
    </div>
  );
}